import{_ as e}from"./plugin-vue_export-helper.21dcd24c.js";import{o as t,c as r,e as a}from"./app.dbe422c1.js";const i={},I=a('<h1 id="_14-1-flutter-ui-\u6846\u67B6-framework" tabindex="-1"><a class="header-anchor" href="#_14-1-flutter-ui-\u6846\u67B6-framework" aria-hidden="true">#</a> 14.1 Flutter UI \u6846\u67B6\uFF08Framework\uFF09</h1><p>\u5728\u672C\u4E66\u7684\u5F00\u59CB\uFF0C\u6211\u4EEC\u8BB2\u8FC7 Flutter \u4ECE\u4E0A\u5230\u4E0B\u5206\u4E3A\u6846\u67B6\u5C42\u3001\u5F15\u64CE\u5C42\u548C\u5D4C\u5165\u5C42\u4E09\u5C42\u3002\u4E5F\u8BF4\u8FC7\u5F00\u53D1\u8005\u57FA\u672C\u4E0A\u90FD\u662F\u4E0E\u6846\u67B6\u5C42\u6253\u4EA4\u9053\uFF0C\u672C\u7AE0\u5C06\u6DF1\u5165\u4ECB\u7ECD\u4E00\u4E0B Flutter \u6846\u67B6\u5C42\u7684\u539F\u7406\uFF0C\u5728\u6B64\u4E4B\u524D\uFF0C\u6211\u4EEC\u5148\u770B\u770B\u66F4\u5E7F\u4E49\u7684UI\u6846\u67B6\u6307\u7684\u662F\u4EC0\u4E48\uFF1F\u89E3\u51B3\u4E86\u4EC0\u4E48\u95EE\u9898\uFF1F</p><p>\u672F\u8BED UI \u6846\u67B6\uFF08UI Framework\uFF09\u7279\u6307\uFF1A\u57FA\u4E8E\u4E00\u4E2A\u5E73\u53F0\uFF0C\u5728\u6B64\u5E73\u53F0\u4E0A\u5B9E\u73B0\u4E00\u4E2A\u80FD<strong>\u5FEB\u901F\u5F00\u53D1</strong>GUI\uFF08\u56FE\u5F62\u7528\u6237\u63A5\u53E3\uFF09\u7684\u6846\u67B6\uFF0C\u8FD9\u91CC\u7684\u5E73\u53F0\u4E3B\u8981\u6307\u64CD\u4F5C\u7CFB\u7EDF\u548C\u6D4F\u89C8\u5668\u3002\u901A\u5E38\u6765\u8BB2\u5E73\u53F0\u53EA\u63D0\u4F9B\u975E\u5E38\u57FA\u7840\u7684\u56FE\u5F62 API\uFF0C\u6BD4\u5982\u753B\u7EBF\u3001\u753B\u51E0\u4F55\u56FE\u5F62\u7B49\uFF0C\u5728\u5927\u591A\u6570\u5E73\u53F0\u4E2D\uFF0C\u8FD9\u4E9B\u57FA\u7840\u7684\u56FE\u5F62 API \u901A\u5E38\u4F1A\u88AB\u5C01\u88C5\u5728\u4E00\u4E2A Canvas \u5BF9\u8C61\u4E2D\u6765\u96C6\u4E2D\u7BA1\u7406\u3002\u53EF\u4EE5\u60F3\u8C61\u4E00\u4E0B\uFF0C\u5982\u679C\u6CA1\u6709UI \u6846\u67B6\u7684\u5C01\u88C5\u800C\u76F4\u63A5\u7528 Canvas \u6765\u6784\u5EFA\u7528\u6237\u754C\u9762\u5C06\u4F1A\u662F\u600E\u6837\u7684\u4E00\u4E2A\u4F53\u9A8C\u548C\u6548\u7387\uFF01 \u6240\u4EE5\uFF0C\u7B80\u5355\u6765\u8BB2\uFF0C UI \u6846\u67B6\u89E3\u51B3\u7684\u4E3B\u8981\u95EE\u9898\u5C31\u662F\uFF1A<strong>\u5982\u4F55\u57FA\u4E8E\u57FA\u7840\u7684\u56FE\u5F62API\uFF08Canvas\uFF09\u6765\u5C01\u88C5\u4E00\u5957\u53EF\u4EE5\u9AD8\u6548\u521B\u5EFAUI\u7684\u6846\u67B6</strong>\u3002</p><p>\u6211\u4EEC\u8BF4\u8FC7\u5404\u4E2A\u5E73\u53F0 UI \u6846\u67B6\u7684\u5B9E\u73B0\u539F\u7406\u57FA\u672C\u662F\u76F8\u901A\u7684\uFF0C\u4E5F\u5C31\u662F\u8BF4\u65E0\u8BBA\u662F Android \u8FD8\u662F iOS\uFF0C\u4ED6\u4EEC\u5C06\u4E00\u4E2A\u7528\u6237\u754C\u9762\u5C55\u793A\u5230\u5C4F\u5E55\u7684\u6D41\u7A0B\u662F\u76F8\u4F3C\u7684\uFF0C\u6240\u4EE5\uFF0C\u5728\u4ECB\u7ECDFlutter UI\u6846\u67B6\u4E4B\u524D\uFF0C\u6211\u4EEC\u5148\u770B\u770B\u5E73\u53F0\u56FE\u5F62\u5904\u7406\u7684\u57FA\u672C\u539F\u7406\uFF0C\u8FD9\u6837\u53EF\u4EE5\u5E2E\u52A9\u8BFB\u8005\u5BF9\u64CD\u4F5C\u7CFB\u7EDF\u548C\u7CFB\u7EDF\u5E95\u5C42UI\u903B\u8F91\u6709\u4E00\u4E2A\u6E05\u6670\u7684\u8BA4\u8BC6\u3002</p><h3 id="\u786C\u4EF6\u7ED8\u56FE\u57FA\u672C\u539F\u7406" tabindex="-1"><a class="header-anchor" href="#\u786C\u4EF6\u7ED8\u56FE\u57FA\u672C\u539F\u7406" aria-hidden="true">#</a> \u786C\u4EF6\u7ED8\u56FE\u57FA\u672C\u539F\u7406</h3><p>\u63D0\u5230\u539F\u7406\uFF0C\u6211\u4EEC\u8981\u4ECE\u5C4F\u5E55\u663E\u793A\u56FE\u50CF\u7684\u57FA\u672C\u539F\u7406\u8C08\u8D77\u3002\u6211\u4EEC\u77E5\u9053\u663E\u793A\u5668\uFF08\u5C4F\u5E55\uFF09\u662F\u7531\u4E00\u4E2A\u4E2A\u7269\u7406\u663E\u793A\u5355\u5143\u7EC4\u6210\uFF0C\u6BCF\u4E00\u4E2A\u5355\u5143\u6211\u4EEC\u53EF\u4EE5\u79F0\u4E4B\u4E3A\u4E00\u4E2A\u7269\u7406\u50CF\u7D20\u70B9\uFF0C\u800C\u6BCF\u4E00\u4E2A\u50CF\u7D20\u70B9\u53EF\u4EE5\u53D1\u51FA\u591A\u79CD\u989C\u8272\uFF0C\u663E\u793A\u5668\u6210\u76F8\u7684\u539F\u7406\u5C31\u662F\u5728\u4E0D\u540C\u7684\u7269\u7406\u50CF\u7D20\u70B9\u4E0A\u663E\u793A\u4E0D\u540C\u7684\u989C\u8272\uFF0C\u6700\u7EC8\u6784\u6210\u5B8C\u6574\u7684\u56FE\u50CF\u3002</p><p>\u4E00\u4E2A\u50CF\u7D20\u70B9\u80FD\u53D1\u51FA\u7684\u6240\u6709\u989C\u8272\u603B\u6570\u662F\u663E\u793A\u5668\u7684\u4E00\u4E2A\u91CD\u8981\u6307\u6807\uFF0C\u6BD4\u5982\u6211\u4EEC\u6240\u8BF4\u76841600\u4E07\u8272\u7684\u5C4F\u5E55\u5C31\u662F\u6307\u4E00\u4E2A\u50CF\u7D20\u70B9\u53EF\u4EE5\u663E\u793A\u51FA1600\u4E07\u79CD\u989C\u8272\uFF0C\u800C\u663E\u793A\u5668\u989C\u8272\u662F\u6709RGB\u4E09\u57FA\u8272\u7EC4\u6210\uFF0C\u6240\u4EE51600\u4E07\u53732\u768424\u6B21\u65B9\uFF0C\u5373\u6BCF\u4E2A\u57FA\u672C\u8272\uFF08R\u3001G\u3001B\uFF09\u6DF1\u5EA6\u6269\u5C55\u81F38 bit(\u4F4D)\uFF0C\u989C\u8272\u6DF1\u5EA6\u8D8A\u6DF1\uFF0C\u6240\u80FD\u663E\u793A\u7684\u8272\u5F69\u66F4\u52A0\u4E30\u5BCC\u9753\u4E3D\u3002</p><p>\u4E3A\u4E86\u66F4\u65B0\u663E\u793A\u753B\u9762\uFF0C\u663E\u793A\u5668\u662F\u4EE5\u56FA\u5B9A\u7684\u9891\u7387\u5237\u65B0\uFF08\u4ECEGPU\u53D6\u6570\u636E\uFF09\uFF0C\u6BD4\u5982\u6709\u4E00\u90E8\u624B\u673A\u5C4F\u5E55\u7684\u5237\u65B0\u9891\u7387\u662F 60Hz\u3002\u5F53\u4E00\u5E27\uFF08frame\uFF09\u56FE\u50CF\u7ED8\u5236\u5B8C\u6BD5\u540E\u51C6\u5907\u7ED8\u5236\u4E0B\u4E00\u5E27\u65F6\uFF0C\u663E\u793A\u5668\u4F1A\u53D1\u51FA\u4E00\u4E2A\u5782\u76F4\u540C\u6B65\u4FE1\u53F7\uFF08\u5982vsync\uFF09\uFF0C 60Hz\u7684\u5C4F\u5E55\u5C31\u4F1A\u4E00\u79D2\u5185\u53D1\u51FA 60\u6B21\u8FD9\u6837\u7684\u4FE1\u53F7\u3002\u800C\u8FD9\u4E2A\u4FE1\u53F7\u4E3B\u8981\u662F\u7528\u4E8E\u540C\u6B65CPU\u3001GPU\u548C\u663E\u793A\u5668\u7684\u3002\u4E00\u822C\u5730\u6765\u8BF4\uFF0C\u8BA1\u7B97\u673A\u7CFB\u7EDF\u4E2D\uFF0CCPU\u3001GPU\u548C\u663E\u793A\u5668\u4EE5\u4E00\u79CD\u7279\u5B9A\u7684\u65B9\u5F0F\u534F\u4F5C\uFF1ACPU\u5C06\u8BA1\u7B97\u597D\u7684\u663E\u793A\u5185\u5BB9\u63D0\u4EA4\u7ED9 GPU\uFF0CGPU\u6E32\u67D3\u540E\u653E\u5165\u5E27\u7F13\u51B2\u533A\uFF0C\u7136\u540E\u89C6\u9891\u63A7\u5236\u5668\u6309\u7167\u540C\u6B65\u4FE1\u53F7\u4ECE\u5E27\u7F13\u51B2\u533A\u53D6\u5E27\u6570\u636E\u4F20\u9012\u7ED9\u663E\u793A\u5668\u663E\u793A\u3002</p><p>CPU\u548CGPU\u7684\u4EFB\u52A1\u662F\u5404\u6709\u504F\u91CD\u7684\uFF0CCPU\u4E3B\u8981\u7528\u4E8E\u57FA\u672C\u6570\u5B66\u548C\u903B\u8F91\u8BA1\u7B97\uFF0C\u800CGPU\u4E3B\u8981\u6267\u884C\u548C\u56FE\u5F62\u5904\u7406\u76F8\u5173\u7684\u590D\u6742\u7684\u6570\u5B66\uFF0C\u5982\u77E9\u9635\u53D8\u5316\u548C\u51E0\u4F55\u8BA1\u7B97\uFF0CGPU\u7684\u4E3B\u8981\u4F5C\u7528\u5C31\u662F\u786E\u5B9A\u6700\u7EC8\u8F93\u9001\u7ED9\u663E\u793A\u5668\u7684\u5404\u4E2A\u50CF\u7D20\u70B9\u7684\u8272\u503C\u3002</p><h3 id="\u64CD\u4F5C\u7CFB\u7EDF\u7ED8\u5236api\u7684\u5C01\u88C5" tabindex="-1"><a class="header-anchor" href="#\u64CD\u4F5C\u7CFB\u7EDF\u7ED8\u5236api\u7684\u5C01\u88C5" aria-hidden="true">#</a> \u64CD\u4F5C\u7CFB\u7EDF\u7ED8\u5236API\u7684\u5C01\u88C5</h3><p>\u7531\u4E8E\u6700\u7EC8\u7684\u56FE\u5F62\u8BA1\u7B97\u548C\u7ED8\u5236\u90FD\u662F\u7531\u76F8\u5E94\u7684\u786C\u4EF6\u6765\u5B8C\u6210\uFF0C\u800C\u76F4\u63A5\u64CD\u4F5C\u786C\u4EF6\u7684\u6307\u4EE4\u901A\u5E38\u90FD\u4F1A\u6709\u64CD\u4F5C\u7CFB\u7EDF\u5C4F\u853D\uFF0C\u5E94\u7528\u5F00\u53D1\u8005\u901A\u5E38\u4E0D\u4F1A\u76F4\u63A5\u9762\u5BF9\u786C\u4EF6\uFF0C\u64CD\u4F5C\u7CFB\u7EDF\u5C4F\u853D\u4E86\u8FD9\u4E9B\u5E95\u5C42\u786C\u4EF6\u64CD\u4F5C\u540E\u4F1A\u63D0\u4F9B\u4E00\u4E9B\u5C01\u88C5\u540E\u7684API\u4F9B\u64CD\u4F5C\u7CFB\u7EDF\u4E4B\u4E0A\u7684\u5E94\u7528\u8C03\u7528\uFF0C\u4F46\u662F\u5BF9\u4E8E\u5E94\u7528\u5F00\u53D1\u8005\u6765\u8BF4\uFF0C\u76F4\u63A5\u8C03\u7528\u8FD9\u4E9B\u64CD\u4F5C\u7CFB\u7EDF\u63D0\u4F9B\u7684API\u662F\u6BD4\u8F83\u590D\u6742\u548C\u4F4E\u6548\u7684\uFF0C\u56E0\u4E3A\u64CD\u4F5C\u7CFB\u7EDF\u63D0\u4F9B\u7684API\u5F80\u5F80\u6BD4\u8F83\u57FA\u7840\uFF0C\u76F4\u63A5\u8C03\u7528\u9700\u8981\u4E86\u89E3API\u7684\u5F88\u591A\u7EC6\u8282\u3002\u6B63\u662F\u56E0\u4E3A\u8FD9\u4E2A\u539F\u56E0\uFF0C\u51E0\u4E4E\u6240\u6709\u7528\u4E8E\u5F00\u53D1GUI\u7A0B\u5E8F\u7684\u7F16\u7A0B\u8BED\u8A00\u90FD\u4F1A\u5728\u64CD\u4F5C\u7CFB\u7EDF\u4E4B\u4E0A\u518D\u5C01\u88C5\u4E00\u5C42\uFF0C\u5C06\u64CD\u4F5C\u7CFB\u7EDF\u539F\u751FAPI\u5C01\u88C5\u5728\u4E00\u4E2A\u7F16\u7A0B\u6846\u67B6\u548C\u6A21\u578B\u4E2D\uFF0C\u7136\u540E\u5B9A\u4E49\u4E00\u79CD\u7B80\u5355\u7684\u5F00\u53D1\u89C4\u5219\u6765\u5F00\u53D1GUI\u5E94\u7528\u7A0B\u5E8F\uFF0C\u800C\u8FD9\u4E00\u5C42\u62BD\u8C61\uFF0C\u6B63\u662F\u6211\u4EEC\u6240\u8BF4\u7684\u201CUI\u6846\u67B6\u201D\uFF0C\u5982Android SDK\u6B63\u662F\u5C01\u88C5\u4E86Android\u64CD\u4F5C\u7CFB\u7EDFAPI\uFF0C\u63D0\u4F9B\u4E86\u4E00\u4E2A\u201CUI\u63CF\u8FF0\u6587\u4EF6 XML+Java/Kotlin \u64CD\u4F5C DOM\u201D\u7684UI \u6846\u67B6\uFF0C\u800CiOS\u7684 UIKit \u5BF9 View \u7684\u62BD\u8C61\u4E5F\u662F\u4E00\u6837\u7684\uFF0C\u4ED6\u4EEC\u90FD\u5C06\u64CD\u4F5C\u7CFB\u7EDFAPI\u62BD\u8C61\u6210\u4E00\u4E2A\u57FA\u7840\u5BF9\u8C61\uFF08\u5982\u7528\u4E8E2D\u56FE\u5F62\u7ED8\u5236\u7684Canvas\uFF09\uFF0C\u7136\u540E\u518D\u5B9A\u4E49\u4E00\u5957\u89C4\u5219\u6765\u63CF\u8FF0UI\uFF0C\u5982UI\u6811\u7ED3\u6784\uFF0CUI \u64CD\u4F5C\u7684\u5355\u7EBF\u7A0B\u539F\u5219\u7B49\u3002</p><h3 id="flutter-ui\u6846\u67B6" tabindex="-1"><a class="header-anchor" href="#flutter-ui\u6846\u67B6" aria-hidden="true">#</a> Flutter UI\u6846\u67B6</h3><p>\u6211\u4EEC\u53EF\u4EE5\u770B\u5230\uFF0C\u65E0\u8BBA\u662F Android SDK \u8FD8\u662F iOS \u7684 UIKit \u7684\u804C\u8D23\u90FD\u662F\u76F8\u540C\u7684\uFF0C\u5B83\u4EEC\u53EA\u662F\u8BED\u8A00\u8F7D\u4F53\u548C\u5E95\u5C42\u7684\u7CFB\u7EDF\u4E0D\u540C\u800C\u5DF2\u3002\u90A3\u4E48\u53EF\u4E0D\u53EF\u4EE5\u5B9E\u73B0\u8FD9\u4E48\u4E00\u4E2AUI \u6846\u67B6\uFF1A\u53EF\u4EE5\u4F7F\u7528\u540C\u4E00\u79CD\u7F16\u7A0B\u8BED\u8A00\u5F00\u53D1\uFF0C\u7136\u540E\u9488\u5BF9\u4E0D\u540C\u64CD\u4F5C\u7CFB\u7EDFAPI\u62BD\u8C61\u4E00\u4E2A\u5BF9\u4E0A\u63A5\u53E3\u4E00\u81F4\uFF0C\u5BF9\u4E0B\u9002\u914D\u4E0D\u540C\u64CD\u4F5C\u7CFB\u7EDF\u7684\u7684\u4E2D\u95F4\u5C42\uFF0C\u7136\u540E\u5728\u6253\u5305\u7F16\u8BD1\u65F6\u518D\u4F7F\u7528\u76F8\u5E94\u7684\u4E2D\u95F4\u5C42\u4EE3\u7801\uFF1F\u5982\u679C\u53EF\u4EE5\u505A\u5230\uFF0C\u90A3\u4E48\u6211\u4EEC\u5C31\u53EF\u4EE5\u4F7F\u7528\u540C\u4E00\u5957\u4EE3\u7801\u7F16\u5199\u8DE8\u5E73\u53F0\u7684\u5E94\u7528\u4E86\u3002\u800CFlutter\u7684\u539F\u7406\u6B63\u662F\u5982\u6B64\uFF0C\u5B83\u63D0\u4F9B\u4E86\u4E00\u5957Dart API\uFF0C\u7136\u540E\u5728\u5E95\u5C42\u901A\u8FC7OpenGL\u8FD9\u79CD\u8DE8\u5E73\u53F0\u7684\u7ED8\u5236\u5E93\uFF08\u5185\u90E8\u4F1A\u8C03\u7528\u64CD\u4F5C\u7CFB\u7EDFAPI\uFF09\u5B9E\u73B0\u4E86\u4E00\u5957\u4EE3\u7801\u8DE8\u591A\u7AEF\u3002\u7531\u4E8EDart API\u4E5F\u662F\u8C03\u7528\u64CD\u4F5C\u7CFB\u7EDFAPI\uFF0C\u6240\u4EE5\u5B83\u7684\u6027\u80FD\u63A5\u8FD1\u539F\u751F\u3002</p><blockquote><p>\u6CE8\u610F\uFF0C\u867D\u7136Dart\u662F\u5148\u8C03\u7528\u4E86OpenGL\uFF0COpenGL\u624D\u4F1A\u8C03\u7528\u64CD\u4F5C\u7CFB\u7EDFAPI\uFF0C\u4F46\u662F\u8FD9\u4ECD\u7136\u662F\u539F\u751F\u6E32\u67D3\uFF0C\u56E0\u4E3AOpenGL\u53EA\u662F\u64CD\u4F5C\u7CFB\u7EDFAPI\u7684\u4E00\u4E2A\u5C01\u88C5\u5E93\uFF0C\u5B83\u5E76\u4E0D\u50CFWebView\u6E32\u67D3\u90A3\u6837\u9700\u8981 JavaScript \u8FD0\u884C\u73AF\u5883\u548CCSS\u6E32\u67D3\u5668\uFF0C\u6240\u4EE5\u4E0D\u4F1A\u6709\u6027\u80FD\u635F\u5931\u3002</p></blockquote><p>\u81F3\u6B64\uFF0C\u6211\u4EEC\u5DF2\u7ECF\u4ECB\u7ECD\u4E86Flutter UI \u6846\u67B6\u548C\u64CD\u4F5C\u7CFB\u7EDF\u4EA4\u4E92\u7684\u8FD9\u4E00\u90E8\u5206\u539F\u7406\uFF0C\u73B0\u5728\u9700\u8981\u8BF4\u4E00\u4E9B\u5B83\u5BF9\u5E94\u7528\u5F00\u53D1\u8005\u5B9A\u4E49\u7684\u5F00\u53D1\u6807\u51C6\u3002\u5176\u5B9E\u5728\u524D\u9762\u7684\u7AE0\u8282\u4E2D\uFF0C\u6211\u4EEC\u5DF2\u7ECF\u5BF9\u8FD9\u4E2A\u6807\u51C6\u975E\u5E38\u719F\u6089\u4E86, \u7B80\u5355\u6982\u62EC\u5C31\u662F\uFF1A\u7EC4\u5408\u548C\u54CD\u5E94\u5F0F\u3002\u6211\u4EEC\u8981\u5F00\u53D1\u4E00\u4E2AUI\u754C\u9762\uFF0C\u9700\u8981\u901A\u8FC7\u7EC4\u5408\u5176\u5B83Widget\u6765\u5B9E\u73B0\uFF0CFlutter\u4E2D\uFF0C\u4E00\u5207\u90FD\u662FWidget\uFF0C\u5F53UI\u8981\u53D1\u751F\u53D8\u5316\u65F6\uFF0C\u6211\u4EEC\u4E0D\u53BB\u76F4\u63A5\u4FEE\u6539DOM\uFF0C\u800C\u662F\u901A\u8FC7\u66F4\u65B0\u72B6\u6001\uFF0C\u8BA9Flutter UI \u6846\u67B6\u6765\u6839\u636E\u65B0\u7684\u72B6\u6001\u6765\u91CD\u65B0\u6784\u5EFAUI\u3002</p><p>\u8BB2\u5230\u8FD9\u91CC\uFF0C\u8BFB\u8005\u53EF\u80FD\u53D1\u73B0Flutter UI \u6846\u67B6\u548CFlutter Framework\u7684\u6982\u5FF5\u662F\u5DEE\u4E0D\u591A\u7684\uFF0C\u7684\u786E\u5982\u6B64\uFF0C\u4E4B\u6240\u4EE5\u7528\u201CUI \u6846\u67B6\u201D\uFF0C\u662F\u56E0\u4E3A\u5176\u4ED6\u5E73\u53F0\u4E2D\u53EF\u80FD\u4E0D\u8FD9\u4E48\u53EB\uFF0C\u6211\u4EEC\u53EA\u662F\u4E3A\u4E86\u6982\u5FF5\u7EDF\u4E00\uFF0C\u4FBF\u4E8E\u63CF\u8FF0\uFF0C\u8BFB\u8005\u4E0D\u5FC5\u7EA0\u7ED3\u4E8E\u6982\u5FF5\u672C\u8EAB\u3002</p><p>\u5728\u63A5\u4E0B\u6765\u7684\u5C0F\u8282\u4E2D\uFF0C\u6211\u4EEC\u5148\u8BE6\u7EC6\u4ECB\u7ECD\u4E00\u4E0B<code>Element</code>\u3001<code>RenderObject</code>\uFF0C\u5B83\u4EEC\u662F\u7EC4\u6210Flutter UI \u6846\u67B6\u7684\u57FA\u77F3\u3002\u6700\u540E\u6211\u4EEC\u518D\u5206\u6790\u4E00\u4E0BFlutter\u5E94\u7528\u542F\u52A8\u3001\u66F4\u65B0\u6D41\u7A0B\u3002</p>',17),n=[I];function U(o,d){return t(),r("div",null,n)}var u=e(i,[["render",U],["__file","flutter_ui_system.html.vue"]]);export{u as default};
